from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from typing import List, Optional
from .rag.config import Settings
from .rag.pipeline import Pipeline
import json
from pathlib import Path

class QueryIn(BaseModel):
    question: str = Field(..., min_length=2)
    top_k: Optional[int] = Field(default=None, ge=1, le=20)

class LoadIn(BaseModel):
    documents: List[str]

def load_seed() -> list:
    path = Path(__file__).parent / "data" / "seed_documents.json"
    return json.loads(path.read_text(encoding="utf-8"))

settings = Settings()
pipe = Pipeline(settings, seed_docs=load_seed())

app = FastAPI(title="Agentic RAG API", version="1.0.0")

@app.post("/query")
def query(payload: QueryIn):
    try:
        out = pipe.answer(payload.question, top_k=payload.top_k)
        return out
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Failed to answer: {e}")

@app.post("/load")
def load(payload: LoadIn):
    try:
        n = pipe.add_documents(payload.documents)
        return {"added": n}
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Failed to load docs: {e}")

from typing import List, Dict, Optional
from .retriever import Retriever
from .prompts import rag_prompt, reflection_prompt
from .llm import LocalGenerator

class Agent:
    def __init__(self, retriever: Retriever, generator: LocalGenerator, tools: Dict[str, object]):
        self.retriever = retriever
        self.generator = generator
        self.tools = tools

    def plan(self, question: str) -> str:
        # Very small planner: choose retrieval by default; detect calculator intent
        if any(tok in question.lower() for tok in ["calculate", "compute", "+", "-", "*", "/", "^"]):
            return "use_tool:calculator"
        return "retrieve"

    def act(self, action: str, question: str, top_k: int) -> Dict[str, Optional[str]]:
        obs = None
        contexts: List[str] = []
        try:
            if action == "retrieve":
                contexts = self.retriever.retrieve(question, top_k=top_k)
                prompt = rag_prompt(contexts, question)
                draft = self.generator.generate(prompt)
                return {"draft": draft, "observation": None}
            elif action.startswith("use_tool:"):
                _, tool_name = action.split(":", 1)
                tool = self.tools.get(tool_name)
                if tool is None:
                    return {"draft": f"Tool '{tool_name}' not available.", "observation": None}
                obs = tool.run(question)
                prompt = f"Observation from {tool_name}: {obs}\n\nQuestion: {question}\nAnswer:"
                draft = self.generator.generate(prompt)
                return {"draft": draft, "observation": obs}
            else:
                return {"draft": "Unknown action.", "observation": None}
        except Exception as e:
            return {"draft": f"Error during action '{action}': {e}", "observation": None}

    def reflect(self, question: str, draft: str) -> str:
        try:
            prompt = reflection_prompt(question, draft)
            return self.generator.generate(prompt)
        except Exception:
            return draft  # Fail-safe

from typing import List
import numpy as np
from sentence_transformers import SentenceTransformer

class Embeddings:
    def __init__(self, model_name: str) -> None:
        self.model = SentenceTransformer(model_name)

    def encode(self, texts: List[str]) -> np.ndarray:
        arr = self.model.encode(texts, convert_to_numpy=True).astype('float32')
        if len(arr.shape) == 1:
            arr = np.expand_dims(arr, axis=0)
        return arr

    @property
    def dim(self) -> int:
        return self.model.get_sentence_embedding_dimension()

from transformers import pipeline
from typing import Dict, Any, List

class LocalGenerator:
    def __init__(self, model_name: str):
        self.pipe = pipeline('text2text-generation', model=model_name)

    def generate(self, prompt: str, max_new_tokens: int = 128, temperature: float = 0.7) -> str:
        out = self.pipe(prompt, max_new_tokens=max_new_tokens, do_sample=True, temperature=temperature)
        text = out[0].get('generated_text') or out[0].get('summary_text') or ''
        return text.strip()

from typing import List

def rag_prompt(contexts: List[str], question: str) -> str:
    context = "\n".join(f"- {c}" for c in contexts) if contexts else "No context."
    return f"""You are a helpful assistant that answers using the provided context.
If you don't know, say so briefly.

Context:
{context}

Question: {question}
Answer:
"""

def reflection_prompt(question: str, draft: str) -> str:
    return f"""You wrote the following draft answer:
---
{draft}
---
Double-check for hallucinations or unsupported claims. If something lacks support
from the context, tone it down or say you don't know. Provide a concise, corrected answer.

Question: {question}
Final Answer:
"""

from typing import Any, Dict
from datetime import datetime

class CalculatorTool:
    name = "calculator"
    description = "Evaluate a basic Python arithmetic expression, e.g. '2*(3+4)'."

    def run(self, expression: str) -> str:
        allowed = {k: v for k, v in vars(__builtins__).items() if k in ('abs','round')}
        try:
            result = eval(expression, {'__builtins__': allowed}, {})
            return str(result)
        except Exception as e:
            return f"Calculator error: {e}"

class TimeTool:
    name = "time"
    description = "Return current date-time as ISO string."
    def run(self, _: str = '') -> str:
        return datetime.now().isoformat(timespec='seconds')
